const analytics = Array.isArray($json) ? $json : [];
if (analytics.length === 0) return [];

// Grouper par organization_id
const byOrg = {};
for (const a of analytics) {
  if (!byOrg[a.organization_id]) byOrg[a.organization_id] = [];
  byOrg[a.organization_id].push(a);
}

const results = [];
for (const [org_id, rows] of Object.entries(byOrg)) {
  const total_posts = rows.length;
  const total_likes = rows.reduce((s, r) => s + (r.likes_count || 0), 0);
  const total_comments = rows.reduce((s, r) => s + (r.comments_count || 0), 0);
  const total_shares = rows.reduce((s, r) => s + (r.shares_count || 0), 0);
  const total_impressions = rows.reduce((s, r) => s + (r.impressions_count || 0), 0);
  const avg_engagement = rows.filter(r => r.engagement_rate).length > 0
    ? (rows.reduce((s, r) => s + (r.engagement_rate || 0), 0) / rows.filter(r => r.engagement_rate).length).toFixed(2)
    : '0';

  // Best day of week analysis
  const byDay = { Mon: 0, Tue: 0, Wed: 0, Thu: 0, Fri: 0, Sat: 0, Sun: 0 };
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayCounters = { Mon: 0, Tue: 0, Wed: 0, Thu: 0, Fri: 0, Sat: 0, Sun: 0 };
  for (const r of rows) {
    const day = dayNames[new Date(r.collected_at).getDay()];
    const eng = (r.likes_count || 0) + (r.comments_count || 0) + (r.shares_count || 0);
    byDay[day] = (byDay[day] || 0) + eng;
    dayCounters[day] = (dayCounters[day] || 0) + 1;
  }
  const bestDay = Object.entries(byDay).sort((a, b) => b[1] - a[1])[0];

  const summary_text = `30 derniers jours: ${total_posts} posts analysés. Total: ${total_likes} likes, ${total_comments} commentaires, ${total_shares} partages, ${total_impressions} impressions. Engagement moyen: ${avg_engagement}%. Meilleur jour: ${bestDay ? bestDay[0] + ' (total engagement: ' + bestDay[1] + ')' : 'N/A'}.`;

  results.push({ json: { organization_id: org_id, summary_text } });
}

return results;

const org_id = $('Code - Group by Org & Build Summaries').item.json.organization_id;
const responseText = $json.content && $json.content[0] ? $json.content[0].text : '';

if (!responseText) return [];

try {
  // Extraire le JSON array de la réponse
  const jsonMatch = responseText.match(/\[.*\]/s);
  if (!jsonMatch) return [];

  const insights = JSON.parse(jsonMatch[0]);
  if (!Array.isArray(insights) || insights.length === 0) return [];

  // Garder uniquement les strings
  const validInsights = insights.filter(i => typeof i === 'string' && i.trim().length > 0);
  if (validInsights.length === 0) return [];

  return [{ json: { organization_id: org_id, insights: validInsights.slice(0, 5) } }];
} catch (e) {
  return [];
}
